+#[test]
+fn multiple_extensions_independent() {
+    let mut policy = ExtensionPolicy::default();
+    policy.deny_caps.clear();
+    policy.per_extension.insert(
+        "ext-a".to_string(),
+        ExtensionOverride {
+            deny: vec!["http".to_string()],
+            ..Default::default()
+        },
+    );
+    policy.per_extension.insert(
+        "ext-b".to_string(),
+        ExtensionOverride {
+            allow: vec!["exec".to_string()],
+            ..Default::default()
+        },
