+#[test]
+fn policy_serde_roundtrip_with_overrides() {
+    let mut policy = ExtensionPolicy::default();
+    policy.per_extension.insert(
+        "test-ext".to_string(),
+        ExtensionOverride {
+            mode: Some(ExtensionPolicyMode::Strict),
+            allow: vec!["tool".to_string()],
